import java.nio.file.*;
import java.util.*;
import java.util.stream.*;
import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.node.*;
class CSVToJSONConverter {
    private final ObjectMapper mapper = new ObjectMapper();
    void convert(Path csvPath, Path jsonPath) throws Exception {
        List<String> lines = Files.readAllLines(csvPath);
        if (lines.isEmpty()) { Files.writeString(jsonPath, "[]"); return; }
        String[] headers = lines.get(0).split(",");
        ArrayNode arr = mapper.createArrayNode();
        for (int i = 1; i < lines.size(); i++) {
            if (lines.get(i).isBlank()) continue;
            String[] vals = lines.get(i).split(",");
            ObjectNode n = mapper.createObjectNode();
            for (int j = 0; j < headers.length && j < vals.length; j++)
                n.put(headers[j].trim(), vals[j].trim().replace("\"", ""));
            arr.add(n);
        }
        Files.writeString(jsonPath, mapper.writerWithDefaultPrettyPrinter().writeValueAsString(arr));
    }
}
