import java.util.Optional;
import com.fasterxml.jackson.databind.*;
record StockQuote(String symbol, double price, double changePercent) {}
class RateLimitException extends RuntimeException { RateLimitException(String m) { super(m); } }
class ZerodhaStockClient {
    HttpClient client; ObjectMapper mapper = new ObjectMapper();
    ZerodhaStockClient(HttpClient c) { client = c; }
    Optional<StockQuote> getQuote(String symbol) {
        try {
            HttpRequest req = HttpRequest.newBuilder()
                .uri(URI.create("https://api.zerodha.com/quotes/" + symbol))
                .GET().build();
            HttpResponse<String> resp = client.send(req, HttpResponse.BodyHandlers.ofString());
            return switch (resp.statusCode()) {
                case 200 -> {
                    JsonNode n = mapper.readTree(resp.body());
                    yield Optional.of(new StockQuote(n.path("symbol").asText(),
                        n.path("price").asDouble(), n.path("change").asDouble()));
                }
                case 404 -> Optional.empty();
                case 429 -> throw new RateLimitException("Rate limit exceeded");
                default  -> Optional.empty();
            };
        } catch (IOException | InterruptedException e) { return Optional.empty(); }
    }
}
