        for (int i = 1; i < lines.size(); i++) {
            if (lines.get(i).isBlank()) continue;
            String[] cols = lines.get(i).split(",");
            String sku = cols[0].trim(), qty = cols[1].trim();
            try {
                HttpRequest req = HttpRequest.newBuilder()
                    .uri(java.net.URI.create("https://api.inventory.com/products/" + sku + "/stock"))
                    .POST(HttpRequest.BodyPublishers.ofString("{\"qty\":" + qty + "}"))
                    .header("Content-Type", "application/json").build();
                HttpResponse<String> resp = client.send(req, HttpResponse.BodyHandlers.ofString());
                if (resp.statusCode() == 200) { synced.incrementAndGet(); report.add("OK: " + sku); }
                else report.add("FAIL: " + sku + " HTTP " + resp.statusCode());
            } catch (Exception e) { report.add("ERROR: " + sku); }
        }
        report.add("Synced: " + synced.get() + "/" + (lines.size() - 1));
        Files.write(csvPath.getParent().resolve("sync-report.txt"), report);
        return synced.get();
    }
}
