    @Mock HttpClient client; @Mock HttpResponse<String> response;
    @Captor ArgumentCaptor<HttpRequest> requestCaptor;
    InventorySyncService svc() { return new InventorySyncService(client); }

    @Test void sync_3products_syncs3AndWritesReport(@TempDir Path dir) throws Exception {
        Path csv = dir.resolve("stock.csv");
        Files.writeString(csv, "sku,qty\nP001,50\nP002,12\nP003,60");
        when(response.statusCode()).thenReturn(200);
        when(client.send(any(), any())).thenReturn(response);
        int count = svc().sync(csv);
        assertEquals(3, count);
        Path report = dir.resolve("sync-report.txt");
        assertTrue(Files.exists(report));
        String content = Files.readString(report);
        assertTrue(content.contains("Synced: 3/3"));
    }
    @Test void sync_emptyCSV_syncs0(@TempDir Path dir) throws Exception {
        Path csv = dir.resolve("empty.csv");
        Files.writeString(csv, "sku,qty\n");
        assertEquals(0, svc().sync(csv));
        assertTrue(Files.readString(dir.resolve("sync-report.txt")).contains("Synced: 0/0"));
    }
    @Test void sync_apiReturns500_countsAsFailed(@TempDir Path dir) throws Exception {
        Path csv = dir.resolve("stock.csv");
        Files.writeString(csv, "sku,qty\nP001,50\nP002,12");
        when(response.statusCode()).thenReturn(200, 500);
        when(client.send(any(), any())).thenReturn(response);
        assertEquals(1, svc().sync(csv));  // only P001 succeeds
        assertTrue(Files.readString(dir.resolve("sync-report.txt")).contains("FAIL: P002"));
    }
