        Path csv = dir.resolve("stock.csv");
        Files.writeString(csv, "sku,qty\nTCS-P001,50");
        when(response.statusCode()).thenReturn(200);
        when(client.send(any(), any())).thenReturn(response);
        svc().sync(csv);
        verify(client).send(requestCaptor.capture(), any());
        assertTrue(requestCaptor.getValue().uri().toString().contains("TCS-P001"));
    }
